export const proposalHtml = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<meta name=\"robots\" content=\"noindex,nofollow\">\n<title>MissionReady Partnership Proposal</title>\n<style>\n  :root{\n    --bg:#F6F3EC; --panel:#FFFFFF; --panel2:#FBF8F1;\n    --ink:#1C1F26; --muted:#6B6A61; --faint:#8E8C81;\n    --line:#E4DECF; --line2:#EFEADD;\n    --accent:#A9812E;      /* brass, Kyle */\n    --company:#3D6A8C;     /* steel blue, company + revenue */\n    --dam:#5A7D53;         /* field green, Damien */\n    --good:#2F7A55; --warn:#B0742B;\n    --shadow:0 1px 2px rgba(28,31,38,.04),0 6px 20px rgba(28,31,38,.06);\n    --serif:Georgia,\"Iowan Old Style\",\"Palatino Linotype\",\"Book Antiqua\",serif;\n    --sans:system-ui,-apple-system,\"Segoe UI\",Roboto,Helvetica,Arial,sans-serif;\n    --mono:ui-monospace,\"SF Mono\",\"Cascadia Mono\",Menlo,monospace;\n  }\n  @media (prefers-color-scheme:dark){\n    :root{--bg:#14171C;--panel:#1B1F27;--panel2:#191D24;--ink:#E9E6DE;--muted:#9E9A8F;--faint:#7C7A70;\n      --line:#2A2F39;--line2:#242932;--accent:#CB9C40;--company:#74A3C6;--dam:#87A87E;--good:#54A97E;--warn:#D3A24C;\n      --shadow:0 1px 2px rgba(0,0,0,.3),0 8px 24px rgba(0,0,0,.28);}\n  }\n  :root[data-theme=\"dark\"]{--bg:#14171C;--panel:#1B1F27;--panel2:#191D24;--ink:#E9E6DE;--muted:#9E9A8F;--faint:#7C7A70;\n      --line:#2A2F39;--line2:#242932;--accent:#CB9C40;--company:#74A3C6;--dam:#87A87E;--good:#54A97E;--warn:#D3A24C;\n      --shadow:0 1px 2px rgba(0,0,0,.3),0 8px 24px rgba(0,0,0,.28);}\n  :root[data-theme=\"light\"]{--bg:#F6F3EC;--panel:#FFFFFF;--panel2:#FBF8F1;--ink:#1C1F26;--muted:#6B6A61;--faint:#8E8C81;\n      --line:#E4DECF;--line2:#EFEADD;--accent:#A9812E;--company:#3D6A8C;--dam:#5A7D53;--good:#2F7A55;--warn:#B0742B;\n      --shadow:0 1px 2px rgba(28,31,38,.04),0 6px 20px rgba(28,31,38,.06);}\n  *{box-sizing:border-box}\n  body{margin:0;background:var(--bg);color:var(--ink);font-family:var(--sans);line-height:1.5;\n    -webkit-font-smoothing:antialiased;font-variant-numeric:tabular-nums}\n  .wrap{max-width:1180px;margin:0 auto;padding:34px 22px 60px}\n  header{border-bottom:1px solid var(--line);padding-bottom:22px;margin-bottom:24px}\n  .eyebrow{font:600 11px/1 var(--mono);letter-spacing:.16em;text-transform:uppercase;color:var(--accent)}\n  h1{font:600 32px/1.08 var(--serif);margin:11px 0 6px;text-wrap:balance;letter-spacing:-.01em}\n  .by{color:var(--muted);font-size:14px}\n  .by b{color:var(--ink);font-weight:600}\n  .lede{color:var(--muted);font-size:14.5px;max-width:70ch;margin-top:12px}\n  h2.sec{font:600 12px/1 var(--mono);letter-spacing:.11em;text-transform:uppercase;color:var(--accent);\n    margin:34px 0 14px;display:flex;align-items:center;gap:12px}\n  h2.sec::after{content:\"\";flex:1;height:1px;background:var(--line)}\n  /* terms */\n  .terms{display:grid;grid-template-columns:repeat(2,1fr);gap:14px}\n  .term{background:var(--panel);border:1px solid var(--line);border-radius:12px;padding:16px 17px;box-shadow:var(--shadow)}\n  .term .n{font:600 10.5px/1 var(--mono);letter-spacing:.08em;text-transform:uppercase;color:var(--faint)}\n  .term h3{font:600 16px/1.25 var(--sans);margin:9px 0 6px;letter-spacing:-.01em}\n  .term p{margin:0;font-size:13.5px;color:var(--muted);line-height:1.55}\n  .term .hi{color:var(--accent);font-weight:600}\n  .term.dam .hi{color:var(--dam)}\n  /* summary */\n  .summary{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin:6px 0 4px}\n  .tile{background:var(--panel);border:1px solid var(--line);border-radius:12px;padding:15px 16px;box-shadow:var(--shadow)}\n  .tile .lab{font:600 10.5px/1.3 var(--mono);letter-spacing:.08em;text-transform:uppercase;color:var(--muted)}\n  .tile .big{font:600 26px/1.05 var(--sans);margin-top:9px;letter-spacing:-.01em}\n  .tile .foot{font-size:11.5px;color:var(--faint);margin-top:5px}\n  .tile.k{border-top:3px solid var(--accent)} .tile.c{border-top:3px solid var(--company)}\n  .tile.g{border-top:3px solid var(--good)} .tile.w{border-top:3px solid var(--warn)} .tile.d{border-top:3px solid var(--dam)}\n  .grid{display:grid;grid-template-columns:352px 1fr;gap:22px;align-items:start;margin-top:16px}\n  .card{background:var(--panel);border:1px solid var(--line);border-radius:12px;box-shadow:var(--shadow)}\n  .card h2{font:600 12px/1 var(--mono);letter-spacing:.1em;text-transform:uppercase;color:var(--muted);margin:0;padding:16px 18px 0}\n  .card .body{padding:14px 18px 18px}\n  .ctrls .grp{padding:14px 18px;border-top:1px solid var(--line2)} .ctrls .grp:first-of-type{border-top:0}\n  .glab{font:600 11px/1 var(--mono);letter-spacing:.09em;text-transform:uppercase;color:var(--accent);margin-bottom:6px}\n  .ghint{font-size:11.5px;color:var(--faint);margin-bottom:10px}\n  .row{display:grid;grid-template-columns:1fr auto;align-items:center;gap:6px 10px;margin:13px 0 4px}\n  .row label{font-size:13px;color:var(--ink)}\n  .row .val{font:600 13px/1 var(--mono);color:var(--ink);background:var(--panel2);border:1px solid var(--line);padding:4px 8px;border-radius:6px;min-width:64px;text-align:right}\n  input[type=range]{grid-column:1/3;width:100%;height:22px;-webkit-appearance:none;appearance:none;background:transparent;cursor:pointer;margin:0}\n  input[type=range]::-webkit-slider-runnable-track{height:4px;border-radius:3px;background:var(--line)}\n  input[type=range]::-moz-range-track{height:4px;border-radius:3px;background:var(--line)}\n  input[type=range]::-webkit-slider-thumb{-webkit-appearance:none;appearance:none;width:16px;height:16px;border-radius:50%;background:var(--accent);border:2px solid var(--panel);margin-top:-6px;box-shadow:0 1px 3px rgba(0,0,0,.25)}\n  input[type=range]::-moz-range-thumb{width:14px;height:14px;border-radius:50%;background:var(--accent);border:2px solid var(--panel)}\n  input[type=range].auto::-webkit-slider-thumb{background:var(--company)}\n  input[type=range].auto::-moz-range-thumb{background:var(--company)}\n  input[type=range]:focus-visible{outline:2px solid var(--accent);outline-offset:4px;border-radius:6px}\n  .presets{display:flex;gap:8px;flex-wrap:wrap;margin-top:4px}\n  .pbtn{font:600 12px/1 var(--sans);padding:8px 11px;border-radius:8px;border:1px solid var(--line);background:var(--panel);color:var(--ink);cursor:pointer;transition:.15s;flex:1}\n  .pbtn:hover{border-color:var(--accent);color:var(--accent)}\n  .pbtn.on{background:var(--accent);border-color:var(--accent);color:#fff}\n  :root[data-theme=\"dark\"] .pbtn.on{color:#15181E} :root[data-theme=\"light\"] .pbtn.on{color:#fff}\n  .pkg{background:var(--panel2);border:1px solid var(--line);border-radius:10px;padding:11px 13px;margin-top:2px}\n  .pkg .t{display:flex;justify-content:space-between;align-items:baseline;gap:8px}\n  .pkg .t b{font:600 16px/1 var(--sans);color:var(--accent)}\n  .pkg .t span{font:600 10px/1 var(--mono);letter-spacing:.06em;text-transform:uppercase;color:var(--good)}\n  .pkg small{display:block;font-size:11px;color:var(--faint);margin-top:6px;line-height:1.5}\n  .assume{font-size:12px;color:var(--muted);line-height:1.6}\n  .assume b{color:var(--ink);font-weight:600}\n  .res{display:flex;flex-direction:column;gap:22px}\n  table{width:100%;border-collapse:collapse;font-size:13.5px}\n  th,td{text-align:right;padding:9px 5px;border-bottom:1px solid var(--line2)}\n  th:first-child,td:first-child{text-align:left}\n  thead th{font:600 10px/1.2 var(--mono);letter-spacing:.04em;text-transform:uppercase;color:var(--muted);padding-bottom:8px}\n  tbody tr:last-child td{border-bottom:0}\n  .money{font-variant-numeric:tabular-nums;font-weight:600}\n  .k{color:var(--accent)} .co{color:var(--company)} .dm{color:var(--dam)}\n  .paybars{display:flex;flex-direction:column;gap:12px}\n  .pb .t{display:flex;justify-content:space-between;font-size:13px;margin-bottom:5px}\n  .pb .t .m{font:600 13px/1 var(--mono)}\n  .track{height:12px;border-radius:6px;background:var(--line2);overflow:hidden;display:flex}\n  .seg{height:100%}\n  .splitrow{margin:14px 0 2px}\n  .splitrow .cap{display:flex;justify-content:space-between;font-size:12.5px;color:var(--muted);margin-bottom:5px}\n  .legend{display:flex;gap:14px;flex-wrap:wrap;margin-top:12px;font-size:12px;color:var(--muted)}\n  .legend i{display:inline-block;width:10px;height:10px;border-radius:3px;margin-right:6px;vertical-align:-1px}\n  .note{font-size:12px;color:var(--faint);margin-top:12px;line-height:1.55}\n  .flag{display:inline-flex;align-items:center;gap:6px;font:600 11px/1 var(--mono);letter-spacing:.03em;padding:5px 9px;border-radius:20px;text-transform:uppercase}\n  .flag.ok{background:color-mix(in srgb,var(--good) 15%,transparent);color:var(--good)}\n  .flag.risk{background:color-mix(in srgb,var(--warn) 16%,transparent);color:var(--warn)}\n  canvas{width:100%;height:200px;display:block}\n  .signrow{display:grid;grid-template-columns:1fr 1fr;gap:26px;margin-top:18px}\n  .sign{border-top:1px solid var(--ink);padding-top:8px;font-size:12.5px;color:var(--muted)}\n  .sign b{color:var(--ink)}\n  .flow{list-style:none;padding:0;margin:0;display:grid;gap:11px;counter-reset:f}\n  .flow li{position:relative;padding:15px 17px 15px 56px;background:var(--panel);border:1px solid var(--line);border-radius:12px;box-shadow:var(--shadow);font-size:14px;color:var(--muted);line-height:1.55}\n  .flow li b{color:var(--ink);font-weight:600}\n  .flow li::before{counter-increment:f;content:counter(f);position:absolute;left:16px;top:14px;width:26px;height:26px;border-radius:50%;background:var(--accent);color:#fff;font:600 13px/26px var(--mono);text-align:center}\n  :root[data-theme=\"dark\"] .flow li::before{color:#15181E}\n  @media (prefers-color-scheme:dark){.flow li::before{color:#15181E}}\n  :root[data-theme=\"light\"] .flow li::before{color:#fff}\n  .explain{font-size:14px;color:var(--muted);max-width:76ch;margin:0 0 14px;line-height:1.6}\n  td.exp{color:var(--muted);font-size:12.5px;font-weight:400;text-align:left}\n  footer{margin-top:34px;padding-top:16px;border-top:1px solid var(--line);color:var(--faint);font-size:11.5px;line-height:1.6}\n  @media (max-width:880px){.grid{grid-template-columns:1fr}.summary{grid-template-columns:repeat(2,1fr)}.terms{grid-template-columns:1fr}.signrow{grid-template-columns:1fr}}\n  @media (max-width:520px){.summary{grid-template-columns:1fr}}\n</style>\n</head>\n<body>\n<div class=\"wrap\">\n  <header>\n    <div class=\"eyebrow\">MissionReady &middot; Partnership proposal</div>\n    <h1>Build partnership and fractional-CTO terms</h1>\n    <div class=\"by\">Prepared by <b>Kyle Stephens, StephensCode</b> for <b>Damien O'Connell, DAO Consulting LLC</b> &middot; for your review</div>\n    <div class=\"lede\">This is how I propose we work together so the platform gets built now, without you paying out of pocket month to month. The structure is built to be investor-fundable: I am paid for my work and for running the tech, we both own a piece, and every part of it is a standard arrangement an advisor or an investor recognizes. Below are the terms, why they hold together, and a live model so you can see what they produce at any level of adoption.</div>\n  </header>\n\n  <h2 class=\"sec\">How it works, start to finish</h2>\n  <ol class=\"flow\">\n    <li><b>You sign and put $10,000 down.</b> From a loan or an early backer. That is the only money out of your pocket up front. No monthly payments after it.</li>\n    <li><b>My team builds the platform.</b> Marine veterans running the full tech side. I carry the cost and the risk while it is built, which is why the terms below protect that.</li>\n    <li><b>We launch and Marines start using it.</b> The platform earns from unit licenses and individual subscriptions. Nothing is owed until it is earning.</li>\n    <li><b>The build is paid from what you raise, first.</b> As capital comes in it pays down the $275,000 build. Whatever capital does not cover is recouped from <b>20% of revenue, which stops the moment the build is paid</b> (and in any case no later than month 36, after which any remaining balance becomes a simple note). It is not forever.</li>\n    <li><b>For running the tech ongoing, I am paid a market CTO retainer</b> (8% of revenue as a floor, with a cap that converts it to a fixed fee once the company is large). Fair pay for the job, not a permanent cut of the company.</li>\n    <li><b>I hold a 10% ownership stake</b> as your technical co-founder. That is where I am rewarded for carrying the early risk, and it is why our incentives match: I win by making the company worth more, not by taxing it.</li>\n  </ol>\n\n  <h2 class=\"sec\">The terms I propose</h2>\n  <div class=\"terms\">\n    <div class=\"term\"><div class=\"n\">1 &middot; Up front</div><h3>A small down payment, then no monthly payments</h3>\n      <p><span class=\"hi\">$10,000 at signing</span> from a loan or an early backer. After that, nothing comes out of your pocket month to month.</p></div>\n    <div class=\"term\"><div class=\"n\">2 &middot; The build</div><h3>A $275,000 build, paid from what you raise, then it ends</h3>\n      <p>The full platform is a <span class=\"hi\">$275,000</span> build at my discounted military rate, which includes a modest premium for financing the build and carrying it at 0% interest until revenue repays it. As you raise capital it pays the build down; any remainder is recouped from <span class=\"hi\">20% of revenue that stops once the build is paid</span>, and no later than month 36. Not a permanent charge.</p></div>\n    <div class=\"term\"><div class=\"n\">3 &middot; Running the tech</div><h3>A market CTO retainer, 8% floor with a cap</h3>\n      <p>For running the entire tech side as your fractional CTO, I am paid a retainer of <span class=\"hi\">8% of revenue as a floor</span>, benchmarked to market once a year by mutual written agreement and never reduced below that floor while I serve as CTO. Once the company is larger (annual revenue above $5,000,000) it <span class=\"hi\">converts to a fixed, board-reviewed fee</span> at a comparable market level, so it never becomes an open-ended cut of a big company.</p></div>\n    <div class=\"term\"><div class=\"n\">4 &middot; Ownership</div><h3>A 10% co-founder stake, standard founder equity</h3>\n      <p>A <span class=\"hi\">10% ownership stake</span> as your technical co-founder, where I am rewarded for carrying the early risk. It is <span class=\"hi\">standard founder equity and dilutes alongside yours in future funding rounds</span>; I take no anti-dilution protection. My interests match yours: I win by making the company worth more.</p></div>\n    <div class=\"term\"><div class=\"n\">5 &middot; Nothing hidden</div><h3>Every piece is a standard arrangement</h3>\n      <p>Developer financing that ends, a market CTO retainer with a floor and a cap, and co-founder equity that dilutes like any founder's. <span class=\"hi\">Each is a normal, recognizable arrangement</span>, with no fine print.</p></div>\n    <div class=\"term dam\"><div class=\"n\">6 &middot; Your side</div><h3>No cash risk, and you keep control</h3>\n      <p>You pay nothing you cannot afford, you keep the large majority of revenue, and you own <span class=\"hi\">90% of the company</span> and keep control. The IP is fully assigned to the company and the recoupment ends, which is exactly the clean structure a funder looks for.</p></div>\n  </div>\n\n  <h2 class=\"sec\">The growth commitment (required, both sides)</h2>\n  <p class=\"explain\">Because my pay comes from revenue and not fixed fees, growth is not optional, it is the deal. We both commit in writing to putting MissionReady in front of as many military members as possible, as fast as possible.</p>\n  <div class=\"terms\">\n    <div class=\"term dam\"><div class=\"n\">Damien commits to</div><h3>Active distribution at every engagement</h3><p>Demo the app and hand out access by QR code and free trial at <span class=\"hi\">every workshop, PME session, and unit visit</span>. Use the senior advisor bench for introductions to units, Training and Education Command, and recruiting command. Run the freemium funnel and the content marketing.</p></div>\n    <div class=\"term dam\"><div class=\"n\">Damien commits to</div><h3>Actively pursuing funding</h3><p>Keep the investor and funding pipeline moving so the build and the growth stay capitalized, and report progress on a regular cadence.</p></div>\n    <div class=\"term\"><div class=\"n\">Kyle commits to</div><h3>Building and running the tech</h3><p>Deliver the platform, keep it running and updated, and provide the <span class=\"hi\">usage data and analytics</span> that back the sales and investor conversations. Mutual 30-day cure periods apply to both the delivery and the marketing commitments.</p></div>\n    <div class=\"term\"><div class=\"n\">Shared floor</div><h3>A minimum adoption target, with teeth</h3><p>We set a minimum adoption floor of <span class=\"hi\">2,500 active users or $20,000 in monthly revenue by month 12</span>. If distribution falls below that floor for reasons within Damien's marketing commitment, the build-recoupment share holds at 20% (it does not step down early) and Damien's distribution exclusivity lapses so Kyle may open other channels, until adoption recovers.</p></div>\n  </div>\n\n  <h2 class=\"sec\">How money we raise is used</h2>\n  <p class=\"explain\">When you raise capital, here is where it goes. Money paid to my team for the build counts toward the $275,000 build, so it lowers what later comes out of revenue and shortens how long the revenue share runs. Money for infrastructure and launch gets the platform live so it can start earning. Here is a $50,000 raise as an example.</p>\n  <section class=\"card\"><div class=\"body\">\n    <table>\n      <thead><tr><th>Where the $50,000 goes</th><th>Amount</th><th>What it does</th></tr></thead>\n      <tbody>\n        <tr><td>Down payment to StephensCode</td><td class=\"money\">$10,000</td><td class=\"exp\">Signing payment; counts toward the $275K build</td></tr>\n        <tr><td>Build funding to StephensCode</td><td class=\"money\">$28,000</td><td class=\"exp\">Pays down more of the build up front; also counts toward the $275K</td></tr>\n        <tr><td>Infrastructure and launch</td><td class=\"money\">$7,000</td><td class=\"exp\">Servers, deployment, app stores, go-live</td></tr>\n        <tr><td>Working capital and reserve</td><td class=\"money\">$5,000</td><td class=\"exp\">Buffer for the first months</td></tr>\n        <tr><td><b>Total raised</b></td><td class=\"money\"><b>$50,000</b></td><td class=\"exp\">Build left to recoup from revenue: about $237,000</td></tr>\n      </tbody>\n    </table>\n    <p class=\"note\">This split is a starting point. If the priority is de-risking the build, more of the raise goes to StephensCode; if the priority is faster growth, more goes to launch and marketing. An investor who puts in the $50,000 receives equity and a return on top, separate from how the cash is used here. The live model below shows the conservative case where only the $10,000 down payment is applied up front (the slowest possible recoupment); any build funding you raise, like the $28,000 above, is applied to the build and shortens it.</p>\n  </div></section>\n\n  <h2 class=\"sec\">What the terms produce (live model)</h2>\n  <div class=\"summary\" id=\"summary\"></div>\n\n  <div class=\"grid\">\n    <section class=\"card ctrls\">\n      <h2>Adjust any lever</h2>\n      <div class=\"grp\">\n        <div class=\"glab\">Adoption (the real variable)</div>\n        <div class=\"ghint\">Start here. Pick a scenario, or set the growth yourself. This is what drives the outcome.</div>\n        <div class=\"presets\">\n          <button class=\"pbtn\" data-preset=\"cons\">Conservative</button>\n          <button class=\"pbtn on\" data-preset=\"mod\">Moderate</button>\n          <button class=\"pbtn\" data-preset=\"strong\">Strong</button>\n        </div>\n        <div class=\"row\"><label>Starting active users</label><span class=\"val\" id=\"v_start\">200</span>\n          <input type=\"range\" id=\"start\" min=\"25\" max=\"2000\" step=\"25\" value=\"200\"></div>\n        <div class=\"row\"><label>New users per month</label><span class=\"val\" id=\"v_grow\">250</span>\n          <input type=\"range\" id=\"grow\" min=\"10\" max=\"1500\" step=\"10\" value=\"250\"></div>\n        <div class=\"row\"><label>Revenue per user / month</label><span class=\"val\" id=\"v_arpu\">$8</span>\n          <input type=\"range\" id=\"arpu\" min=\"3\" max=\"20\" step=\"0.5\" value=\"8\"></div>\n      </div>\n      <div class=\"grp\">\n        <div class=\"glab\">The deal terms (interlocked)</div>\n        <div class=\"ghint\">Move any one and the others rebalance so my overall package stays the same. You can change how I am paid, not how much. The rebalanced lever moves in blue.</div>\n        <div class=\"row\"><label>Phase A share (recoup build)</label><span class=\"val\" id=\"v_pa\">20%</span>\n          <input type=\"range\" id=\"pa\" min=\"15\" max=\"25\" step=\"1\" value=\"20\"></div>\n        <div class=\"row\"><label>CTO retainer (of revenue)</label><span class=\"val\" id=\"v_pb\">8%</span>\n          <input type=\"range\" id=\"pb\" min=\"8\" max=\"14\" step=\"1\" value=\"8\"></div>\n        <div class=\"row\"><label>Build value / recoup at</label><span class=\"val\" id=\"v_thr\">$275K</span>\n          <input type=\"range\" id=\"thr\" min=\"250000\" max=\"350000\" step=\"5000\" value=\"275000\"></div>\n        <div class=\"row\"><label>Down payment</label><span class=\"val\" id=\"v_down\">$10K</span>\n          <input type=\"range\" id=\"down\" min=\"0\" max=\"40000\" step=\"2500\" value=\"10000\"></div>\n        <div class=\"row\"><label>Kyle equity stake</label><span class=\"val\" id=\"v_eq\">10%</span>\n          <input type=\"range\" id=\"eq\" min=\"8\" max=\"15\" step=\"1\" value=\"10\"></div>\n        <div class=\"pkg\" id=\"pkg\"></div>\n      </div>\n      <div class=\"grp\">\n        <div class=\"glab\">Company assumptions (fixed)</div>\n        <p class=\"assume\">Infrastructure is treated as a company cost at <b>15% of revenue</b>. Company value is shown at a <b>5x</b> annual-revenue multiple, a simple directional yardstick, not a formal appraisal. Growth saturates toward a realistic ceiling and reflects ongoing monthly churn, so the curve does not run away.</p>\n      </div>\n    </section>\n\n    <div class=\"res\">\n      <section class=\"card\">\n        <h2>Revenue, valuation, and who keeps what</h2>\n        <div class=\"body\">\n          <table>\n            <thead><tr><th>Milestone</th><th>Users</th><th>Revenue / mo</th><th>ARR</th><th>Company gross margin / mo</th><th>Company value</th></tr></thead>\n            <tbody id=\"fc\"></tbody>\n          </table>\n          <canvas id=\"chart\" width=\"740\" height=\"200\" aria-label=\"Monthly revenue over five years with the build-payoff month marked\"></canvas>\n          <div class=\"legend\">\n            <span><i style=\"background:var(--company)\"></i>Monthly revenue</span>\n            <span id=\"leg_payoff\"><i style=\"background:var(--accent)\"></i>Build paid off, my share steps down to the retainer</span>\n          </div>\n          <p class=\"note\">Company gross margin is revenue after my share and infrastructure, before other operating costs (content, marketing, support, staffing). It is not take-home profit.</p>\n        </div>\n      </section>\n\n      <section class=\"card\">\n        <h2>How each dollar of revenue splits</h2>\n        <div class=\"body\">\n          <div class=\"splitrow\" id=\"splitA\"></div>\n          <div class=\"splitrow\" id=\"splitB\"></div>\n          <div class=\"legend\">\n            <span><i style=\"background:var(--accent)\"></i>Kyle</span>\n            <span><i style=\"background:var(--company)\"></i>Infrastructure</span>\n            <span><i style=\"background:var(--dam)\"></i>Company (gross margin)</span>\n          </div>\n        </div>\n      </section>\n\n      <section class=\"card\">\n        <h2>Kyle's compensation over 5 years</h2>\n        <div class=\"body\">\n          <div id=\"recoupflag\" style=\"margin-bottom:14px\"></div>\n          <div class=\"paybars\" id=\"pay\"></div>\n          <div class=\"note\" id=\"paynote\"></div>\n        </div>\n      </section>\n    </div>\n  </div>\n\n  <h2 class=\"sec\">Protections for both of us</h2>\n  <div class=\"terms\">\n    <div class=\"term\"><div class=\"n\">Phased and funded</div><h3>The build proceeds as it is funded</h3><p>We build in stages tied to funding, starting with a working demo. Neither of us is over-exposed: <span class=\"hi\">you never owe for work that is not funded, and I never build the whole platform on spec</span> before there is money or momentum behind it.</p></div>\n    <div class=\"term\"><div class=\"n\">If the raise stalls</div><h3>An unrecouped balance becomes a simple note</h3><p>If capital is not raised and the build is not recouped from revenue by month 36, any remaining balance becomes a <span class=\"hi\">simple note payable when you next raise or on a sale</span>. Your ownership of the platform is unaffected, and the 20% revenue share still ends at month 36 either way.</p></div>\n    <div class=\"term\"><div class=\"n\">Earned, not gifted</div><h3>My 10% vests as I deliver</h3><p>My equity vests over the build and my time as CTO, so I earn it by doing the work. If I ever walk away, I keep only what I have earned. <span class=\"hi\">If the company is sold, it vests in full.</span></p></div>\n    <div class=\"term\"><div class=\"n\">The company owns it</div><h3>All the code and IP belong to the company</h3><p>Everything I build is assigned to the company, not held by StephensCode. <span class=\"hi\">You own the platform outright</span>, which is exactly what an investor or an acquirer needs to see.</p></div>\n    <div class=\"term\"><div class=\"n\">If either side needs to stop</div><h3>A clean pause, and a clean exit</h3><p>Either of us can pause during a funding gap: a pause stops the clock without forfeiting vesting. If the project is ended for convenience, the unrecouped build value settles on the same note terms, with a clean handoff so neither side is left stuck.</p></div>\n    <div class=\"term\"><div class=\"n\">Your minority is protected too</div><h3>Tag-along and basic information rights</h3><p>If you sell your stake, I can sell my 10% on the same terms (tag-along), and a sale cannot be structured to strand the minority. I get <span class=\"hi\">basic information rights</span>: annual and quarterly financials, and the cap table on request. These are ordinary founder-minority terms an investor expects.</p></div>\n  </div>\n\n  <h2 class=\"sec\">Agreement</h2>\n  <p style=\"font-size:13.5px;color:var(--muted);max-width:74ch;margin:0 0 4px\">These terms lay out the shape of the deal in plain language. We put the final numbers in a signed agreement, ideally with each of us having it looked over, before anything is locked. The figures above reflect the current settings in the model.</p>\n  <div class=\"signrow\">\n    <div class=\"sign\"><b>Damien O'Connell</b>, DAO Consulting LLC<br>Signature and date</div>\n    <div class=\"sign\"><b>Kyle Stephens</b>, StephensCode<br>Signature and date</div>\n  </div>\n\n  <footer id=\"foot\"></footer>\n</div>\n\n<script>\n(function(){\n  // ----- constants -----\n  var MONTHS=60, LONGSTOP=36;                 // 20% share ends at recoup or month 36, whichever first\n  var REF={start:200,grow:250,arpu:8};        // reference adoption (Moderate) for the conserved package value\n  var CAP=50000, CHURN=0.02;                  // TAM ceiling and monthly churn so growth saturates\n  var INFRA=15, MULT=5;                       // fixed company assumptions\n  var PRESETS={cons:{start:100,grow:80},mod:{start:200,grow:250},strong:{start:400,grow:650}};\n  var TERMS=[\"pa\",\"pb\",\"thr\",\"down\",\"eq\"], ADOPT=[\"start\",\"grow\",\"arpu\"];\n  var ids=TERMS.concat(ADOPT), el={};\n  ids.forEach(function(i){el[i]=document.getElementById(i);});\n\n  var fmt=function(n){return \"$\"+Math.round(n).toLocaleString(\"en-US\");};\n  var fmtK=function(n){if(n>=1000000)return \"$\"+(n/1000000).toFixed(n<10000000?2:1)+\"M\";\n    if(n>=1000)return \"$\"+Math.round(n/1000)+\"K\";return \"$\"+Math.round(n);};\n  var fmtU=function(n){return Math.round(n).toLocaleString(\"en-US\");};\n  function bmin(id){return +el[id].min;} function bmax(id){return +el[id].max;}\n  function step(id){return +el[id].step||1;}\n  function clampId(v,id){return Math.max(bmin(id),Math.min(bmax(id),v));}\n\n  function readTerms(){return {pa:+el.pa.value,pb:+el.pb.value,thr:+el.thr.value,down:+el.down.value,eq:+el.eq.value};}\n  function readAdopt(){return {start:+el.start.value,grow:+el.grow.value,arpu:+el.arpu.value};}\n\n  // saturating, churned user series\n  function userSeries(ad){\n    var arr=[],u=ad.start;\n    for(var m=1;m<=MONTHS;m++){\n      arr.push(u);\n      var gross=ad.grow*Math.max(0,1-u/CAP);\n      u=Math.max(0,u+gross-CHURN*u);\n    }\n    return arr;\n  }\n\n  // full simulation for a given adoption + terms\n  function sim(ad,t){\n    var users=userSeries(ad);\n    var cum=t.down,recoup=null,paTot=0,pbTot=0,damKeep=0,infraTot=0,series=[],phase=[];\n    for(var m=1;m<=MONTHS;m++){\n      var rev=users[m-1]*ad.arpu, infra=rev*(INFRA/100), share, ph;\n      var inA=(cum<t.thr)&&(m<=LONGSTOP);\n      if(inA){\n        var need=t.thr-cum, full=rev*(t.pa/100);\n        if(full>=need){                        // crossing month: prorate exactly to the build price\n          var usedRev=(t.pa>0)?need/(t.pa/100):0, remRev=Math.max(0,rev-usedRev), ret=remRev*(t.pb/100);\n          paTot+=need; pbTot+=ret; cum=t.thr; recoup=m; share=need+ret; ph=\"A\";\n        } else { share=full; cum+=full; paTot+=full; ph=\"A\"; }\n      } else { share=rev*(t.pb/100); pbTot+=share; ph=\"B\"; }\n      infraTot+=infra; damKeep+=(rev-share-infra);\n      series.push({m:m,rev:rev,phase:ph}); phase.push(ph);\n    }\n    function packm(m){var rev=users[m-1]*ad.arpu, arr=rev*12, val=arr*MULT, r=(phase[m-1]===\"A\"?t.pa:t.pb)/100;\n      return {users:users[m-1],mrr:rev,arr:arr,val:val,eq:val*t.eq/100,damKeep:rev-rev*r-rev*(INFRA/100)};}\n    return {series:series,phase:phase,recoup:recoup,paTot:paTot,pbTot:pbTot,down:t.down,\n      buildCash:t.down+paTot, cash:t.down+paTot+pbTot, shortfall:Math.max(0,t.thr-(t.down+paTot)),\n      damKeep5:damKeep,infra5:infraTot, y1:packm(12),y3:packm(36),y5:packm(60)};\n  }\n\n  // conserved package value: the build (counted at full price, since a note makes Kyle whole),\n  // plus the 5-year retainer and the year-5 equity, all at the reference adoption.\n  function packageValue(t){var r=sim(REF,t); return t.thr + r.pbTot + r.y5.eq;}\n  var V0=packageValue(readTerms());   // anchor value, set once at load\n\n  // interlock: after the user moves term X, adjust a balancer so packageValue returns to V0\n  function balance(movedId){\n    var B=(movedId===\"eq\")?\"thr\":\"eq\";   // primary balancer (both are monotonic-increasing in value)\n    var lo=bmin(B), hi=bmax(B), t=readTerms(), mid=t[B];\n    for(var it=0;it<44;it++){\n      mid=(lo+hi)/2; t[B]=mid;\n      if(packageValue(t)>V0) hi=mid; else lo=mid;\n    }\n    var snapped=clampId(Math.round(mid/step(B))*step(B),B);\n    if(el[B].value!=snapped){el[B].value=snapped;}\n    return B;\n  }\n\n  function tile(cls,lab,big,foot){return \"<div class='tile \"+cls+\"'><div class=lab>\"+lab+\"</div><div class=big>\"+big+\"</div><div class=foot>\"+foot+\"</div></div>\";}\n\n  function render(highlightB){\n    var t=readTerms(), ad=readAdopt(), r=sim(ad,t);\n    document.getElementById(\"v_start\").textContent=fmtU(ad.start);\n    document.getElementById(\"v_grow\").textContent=fmtU(ad.grow);\n    document.getElementById(\"v_arpu\").textContent=\"$\"+ad.arpu;\n    document.getElementById(\"v_pa\").textContent=t.pa+\"%\";\n    document.getElementById(\"v_pb\").textContent=t.pb+\"%\";\n    document.getElementById(\"v_thr\").textContent=fmtK(t.thr);\n    document.getElementById(\"v_down\").textContent=fmtK(t.down);\n    document.getElementById(\"v_eq\").textContent=t.eq+\"%\";\n\n    // mark the auto-balanced slider in blue for one paint\n    TERMS.forEach(function(i){el[i].classList.toggle(\"auto\",i===highlightB);});\n\n    // conserved-package readout\n    var pv=packageValue(t);\n    document.getElementById(\"pkg\").innerHTML=\n      \"<div class=t><b>\"+fmtK(pv)+\"</b><span>package held</span></div>\"+\n      \"<small>My overall package at the reference (Moderate) case. Rebalancing the terms holds this near \"+fmtK(V0)+\n      \"; only adoption above changes what I actually earn.</small>\";\n\n    var total5=r.cash+r.y5.eq;\n    var recoupTxt=r.recoup?(\"Month \"+r.recoup):(r.shortfall>0?\"Note at mo 36\":\"Not in 5 yrs\");\n    var recoupFoot=r.recoup?(\"Year \"+(Math.floor((r.recoup-1)/12)+1)+\", Kyle's risk retired\")\n      :(r.shortfall>0?(\"Balance \"+fmtK(r.shortfall)+\" carried as a note\"):\"Fully recouped\");\n    document.getElementById(\"summary\").innerHTML=\n      tile(\"k\",\"Kyle 5-year cash + equity\",fmtK(total5),\"Cash \"+fmtK(r.cash)+\" plus paper equity \"+fmtK(r.y5.eq))+\n      tile((r.recoup?\"g\":\"w\"),\"Build paid off\",recoupTxt,recoupFoot)+\n      tile(\"d\",\"Company gross margin, 5 yr\",fmtK(r.damKeep5),\"After Kyle's share and infra, before other opex\")+\n      tile(\"c\",\"Company value, yr 5\",fmtK(r.y5.val),fmtK(r.y5.arr)+\" ARR at \"+MULT.toFixed(1)+\"x\");\n\n    function frow(name,d){return \"<tr><td>\"+name+\"</td><td>\"+fmtU(d.users)+\"</td><td class=money>\"+fmt(d.mrr)+\n      \"</td><td class=money>\"+fmt(d.arr)+\"</td><td class='money dm'>\"+fmt(d.damKeep)+\n      \"</td><td class='money co'>\"+fmtK(d.val)+\"</td></tr>\";}\n    document.getElementById(\"fc\").innerHTML=frow(\"Year 1\",r.y1)+frow(\"Year 3\",r.y3)+frow(\"Year 5\",r.y5);\n\n    function split(id,label,kylePct){\n      var inf=INFRA,dam=Math.max(0,100-kylePct-inf);\n      document.getElementById(id).innerHTML=\n        \"<div class=cap><span>\"+label+\"</span><span>Kyle \"+kylePct+\"% &middot; Infra \"+inf+\"% &middot; Company \"+dam+\"%</span></div>\"+\n        \"<div class=track><span class=seg style='width:\"+kylePct+\"%;background:var(--accent)'></span>\"+\n        \"<span class=seg style='width:\"+inf+\"%;background:var(--company)'></span>\"+\n        \"<span class=seg style='width:\"+dam+\"%;background:var(--dam)'></span></div>\";\n    }\n    split(\"splitA\",\"While recouping the build\",t.pa);\n    split(\"splitB\",\"Ongoing, CTO retainer\",t.pb);\n\n    document.getElementById(\"leg_payoff\").innerHTML=\n      \"<i style='background:var(--accent)'></i>Build paid off, my share steps from \"+t.pa+\"% to the \"+t.pb+\"% retainer\";\n\n    document.getElementById(\"recoupflag\").innerHTML=r.recoup\n      ?\"<span class='flag ok'>&#9679; Build recouped month \"+r.recoup+\" &middot; Kyle carries the risk until then</span>\"\n      :\"<span class='flag risk'>&#9679; Build not fully recouped from revenue &middot; \"+fmtK(r.shortfall)+\" carried as a note at month 36</span>\";\n\n    var streams=[{n:\"Down payment\",v:r.down,c:\"var(--faint)\"},\n      {n:\"Phase A share (build recoupment)\",v:r.paTot,c:\"var(--warn)\"},\n      {n:\"CTO retainer, ongoing\",v:r.pbTot,c:\"var(--good)\"},\n      {n:\"Equity value at year 5 (on paper, before dilution)\",v:r.y5.eq,c:\"var(--accent)\"}];\n    var max=Math.max.apply(null,streams.map(function(s){return s.v;}).concat([1]));\n    document.getElementById(\"pay\").innerHTML=streams.map(function(s){\n      var w=Math.max(2,s.v/max*100);\n      return \"<div class=pb><div class=t><b>\"+s.n+\"</b><span class=m>\"+fmt(s.v)+\"</span></div><div class=track><span class=seg style='width:\"+w+\"%;background:\"+s.c+\"'></span></div></div>\";\n    }).join(\"\");\n    document.getElementById(\"paynote\").innerHTML=\"Cash to Kyle over 5 years: <b>\"+fmt(r.cash)+\n      \"</b> (down payment plus revenue share; any unrecouped balance is a note on top). Equity is a paper mark at the year-5 valuation, before future dilution, realized only on a sale. Cash plus paper equity: <b class=k>\"+fmt(total5)+\"</b>.\";\n    document.getElementById(\"foot\").innerHTML=\"Revenue is active users times $\"+ad.arpu+\n      \"/user/month, with growth saturating toward a \"+fmtU(CAP)+\"-user ceiling and \"+(CHURN*100)+\n      \"% monthly churn. Phase A takes \"+t.pa+\"% of revenue toward a \"+fmtK(t.thr)+\" recoupment (the down payment counts), ending at payoff or month 36, then steps to \"+t.pb+\n      \"% ongoing. Infrastructure is a company cost at \"+INFRA+\"% of revenue. Valuation is a simple \"+MULT+\"x ARR multiple and is directional, not a formal appraisal. The deal-term sliders are interlocked to hold Kyle's overall package constant; adoption is the free variable.\";\n    drawChart(r);\n  }\n\n  function cssv(n){return getComputedStyle(document.documentElement).getPropertyValue(n).trim();}\n  function hexA(hex,a){hex=hex.replace('#','');if(hex.length===3)hex=hex.split('').map(function(c){return c+c;}).join('');\n    return \"rgba(\"+parseInt(hex.substr(0,2),16)+\",\"+parseInt(hex.substr(2,2),16)+\",\"+parseInt(hex.substr(4,2),16)+\",\"+a+\")\";}\n  function drawChart(r){\n    var c=document.getElementById(\"chart\"),ctx=c.getContext(\"2d\"),DPR=Math.min(2,window.devicePixelRatio||1);\n    var W=c.clientWidth||740,H=200;c.width=W*DPR;c.height=H*DPR;ctx.setTransform(DPR,0,0,DPR,0,0);ctx.clearRect(0,0,W,H);\n    var padL=8,padR=8,padT=14,padB=18,w=W-padL-padR,h=H-padT-padB;\n    var maxRev=Math.max.apply(null,r.series.map(function(s){return s.rev;}).concat([1])),n=r.series.length;\n    var x=function(i){return padL+w*(i/(n-1));},y=function(v){return padT+h*(1-v/maxRev);};\n    ctx.strokeStyle=cssv(\"--line2\");ctx.lineWidth=1;\n    for(var g=0;g<=3;g++){var yy=padT+h*g/3;ctx.beginPath();ctx.moveTo(padL,yy);ctx.lineTo(W-padR,yy);ctx.stroke();}\n    var grad=ctx.createLinearGradient(0,padT,0,padT+h);grad.addColorStop(0,hexA(cssv(\"--company\"),.28));grad.addColorStop(1,hexA(cssv(\"--company\"),.02));\n    ctx.beginPath();ctx.moveTo(x(0),y(r.series[0].rev));for(var i=1;i<n;i++)ctx.lineTo(x(i),y(r.series[i].rev));\n    ctx.lineTo(x(n-1),padT+h);ctx.lineTo(x(0),padT+h);ctx.closePath();ctx.fillStyle=grad;ctx.fill();\n    ctx.beginPath();ctx.moveTo(x(0),y(r.series[0].rev));for(i=1;i<n;i++)ctx.lineTo(x(i),y(r.series[i].rev));\n    ctx.strokeStyle=cssv(\"--company\");ctx.lineWidth=2;ctx.stroke();\n    if(r.recoup){var xi=x(r.recoup-1);ctx.strokeStyle=cssv(\"--accent\");ctx.lineWidth=2;ctx.setLineDash([4,4]);\n      ctx.beginPath();ctx.moveTo(xi,padT-4);ctx.lineTo(xi,padT+h);ctx.stroke();ctx.setLineDash([]);\n      ctx.fillStyle=cssv(\"--accent\");ctx.beginPath();ctx.arc(xi,y(r.series[r.recoup-1].rev),3.5,0,7);ctx.fill();}\n    ctx.fillStyle=cssv(\"--faint\");ctx.font=\"10px \"+cssv(\"--mono\");ctx.textAlign=\"center\";\n    for(var yr=1;yr<=5;yr++){var mi=yr*12-1;if(mi<n)ctx.fillText(\"Y\"+yr,x(mi),H-5);}\n    ctx.textAlign=\"left\";ctx.fillText(fmtK(maxRev)+\"/mo\",padL+2,padT+8);\n  }\n\n  // events: adoption sliders are free; deal-term sliders interlock\n  ADOPT.forEach(function(i){el[i].addEventListener(\"input\",function(){\n    document.querySelectorAll(\".pbtn\").forEach(function(b){b.classList.remove(\"on\");});\n    render();});});\n  TERMS.forEach(function(i){el[i].addEventListener(\"input\",function(){\n    var B=balance(i); render(B);});});\n  document.querySelectorAll(\".pbtn\").forEach(function(b){b.addEventListener(\"click\",function(){\n    document.querySelectorAll(\".pbtn\").forEach(function(x){x.classList.remove(\"on\");});b.classList.add(\"on\");\n    var pr=PRESETS[b.dataset.preset];el.start.value=pr.start;el.grow.value=pr.grow;render();});});\n  window.addEventListener(\"resize\",function(){render();});\n  var mq=window.matchMedia(\"(prefers-color-scheme:dark)\");mq.addEventListener&&mq.addEventListener(\"change\",function(){render();});\n  new MutationObserver(function(){render();}).observe(document.documentElement,{attributes:true,attributeFilter:[\"data-theme\"]});\n  render();\n})();\n</script>\n</body>\n</html>\n";
